import Foundation

enum SeedCatalog {
    /// Novidades legislativas de 2026: índices oficiais que mudam quando um ato
    /// novo é publicado — a usuária é avisada. As listas de leis/LCs/MPs vêm da
    /// API de dados abertos do Senado (XML estável; o bloco <Metadados> carrega
    /// um timestamp por consulta e é removido via stripPattern). As páginas
    /// equivalentes do Planalto (portal-legis) são shells de JavaScript.
    static func novidades2026() -> [LawEntry] {
        func fonte(_ title: String, _ reference: String, _ url: String,
                   _ term: String, strip: String? = nil) -> LawEntry {
            LawEntry(title: title, reference: reference, category: .especial,
                     sourceURL: url, isBuiltIn: true, monitored: true,
                     docKind: "novidades", validationTerm: term, stripPattern: strip)
        }
        let metadados = "(?s)<Metadados>.*?</Metadados>"
        return [
            fonte("Leis ordinárias de 2026", "Todas as leis federais sancionadas em 2026, com ementa — avisa quando sair lei nova",
                  "https://legis.senado.leg.br/dadosabertos/legislacao/lista?tipo=LEI&ano=2026",
                  "Lei nº", strip: metadados),
            fonte("Leis complementares de 2026", "Leis complementares de 2026, com ementa — avisa quando sair LC nova",
                  "https://legis.senado.leg.br/dadosabertos/legislacao/lista?tipo=LCP&ano=2026",
                  "Lei Complementar", strip: metadados),
            fonte("Medidas provisórias de 2026", "MPs editadas em 2026, com ementa — avisa quando sair MP nova",
                  "https://legis.senado.leg.br/dadosabertos/legislacao/lista?tipo=MPV&ano=2026",
                  "Medida Provisória", strip: metadados),
            fonte("Emendas Constitucionais", "Quadro oficial das ECs no Planalto — avisa quando for promulgada emenda nova",
                  "https://www.planalto.gov.br/ccivil_03/constituicao/emendas/emc/quadro_emc.htm",
                  "Emenda Constitucional"),
        ]
    }

